    55→                       Local<Module> module,
    56→                       Local<String> url,
    57→                       Local<Object> context_object,
    58→                       Local<Value> synthetic_evaluation_step)
    59→    : BaseObject(realm, object),
    60→      module_(realm->isolate(), module),
    61→      module_hash_(module->GetIdentityHash()) {
    62→  realm->env()->hash_to_module_map.emplace(module_hash_, this);
