    96→                                      Local<Module> module) {
    97→  auto range = env->hash_to_module_map.equal_range(module->GetIdentityHash());
    98→  for (auto it = range.first; it != range.second; ++it) {
    99→    if (it->second->module_ == module) {
   100→      return it->second;
   101→    }
   102→  }
   103→  return nullptr;
