   106→v8::Maybe<bool> ModuleWrap::CheckUnsettledTopLevelAwait() {
   107→  Isolate* isolate = env()->isolate();
   108→  Local<Context> context = env()->context();
   109→
   110→  // This must be invoked when the environment is shutting down, and the module
   111→  // is kept alive by the module wrap via an internal field.
   112→  CHECK(env()->exiting());
   113→  CHECK(!module_.IsEmpty());
   114→
   115→  Local<Module> module = module_.Get(isolate);
   116→  // It's a synthetic module, likely a facade wrapping CJS.
   117→  if (!module->IsSourceTextModule()) {
   118→    return v8::Just(true);
   119→  }
   120→
   121→  if (!module->IsGraphAsync()) {  // There is no TLA, no need to check.
   122→    return v8::Just(true);
   123→  }
   124→
   125→  auto stalled_messages =
   126→      std::get<1>(module->GetStalledTopLevelAwaitMessages(isolate));
   127→  if (stalled_messages.empty()) {
   128→    return v8::Just(true);
   129→  }
   130→
   131→  if (env()->options()->warnings) {
   132→    for (auto& message : stalled_messages) {
   133→      std::string reason = "Warning: Detected unsettled top-level await at ";
   134→      std::string info =
   135→          FormatErrorMessage(isolate, context, "", message, true);
   136→      reason += info;
   137→      FPrintF(stderr, "%s\n", reason);
   138→    }
   139→  }
   140→
   141→  return v8::Just(false);
   142→}
