   145→    Isolate* isolate, Local<Symbol> id_symbol) {
   146→  Local<PrimitiveArray> host_defined_options =
   147→      PrimitiveArray::New(isolate, HostDefinedOptions::kLength);
   148→  host_defined_options->Set(isolate, HostDefinedOptions::kID, id_symbol);
   149→  return host_defined_options;
   150→}

